("How do I handle date columns with multiple formats?",
 'import pandas as pd\n\ndef parse_flexible_date(series):\n    """Try multiple date formats until one works."""\n    formats = ["%Y-%m-%d", "%d/%m/%Y", "%m/%d/%Y", "%Y%m%d", "%d-%b-%Y"]\n    result = pd.Series([pd.NaT] * len(series))\n    for fmt in formats:\n        mask = result.isna()\n        try:\n            parsed = pd.to_datetime(series[mask], format=fmt, errors="coerce")\n            result[mask] = parsed\n        except Exception:\n            pass\n    # Final fallback: pandas auto-detect\n    still_missing = result.isna()\n    result[still_missing] = pd.to_datetime(series[still_missing], errors="coerce", infer_datetime_format=True)\n    print(f"Parsed: {result.notna().sum()}/{len(series)} ({result.isna().sum()} failed)")\n    return result\n\ndf["date_parsed"] = parse_flexible_date(df["date_raw"])', "advanced"),

