("How do I create geospatial features from latitude/longitude?",
 'import numpy as np\nimport pandas as pd\n\n# Haversine distance to city center\ndef haversine(lat1, lon1, lat2, lon2):\n    R = 6371  # Earth radius km\n    dlat = np.radians(lat2 - lat1)\n    dlon = np.radians(lon2 - lon1)\n    a = np.sin(dlat/2)**2 + np.cos(np.radians(lat1)) * np.cos(np.radians(lat2)) * np.sin(dlon/2)**2\n    return 2 * R * np.arcsin(np.sqrt(a))\n\n# NYC center\nNYC_LAT, NYC_LON = 40.7128, -74.0060\ndf["dist_to_nyc_km"] = haversine(df["latitude"], df["longitude"], NYC_LAT, NYC_LON)\nprint(df[["latitude","longitude","dist_to_nyc_km"]].head())', "advanced"),

